import { useNavigate } from "react-router-dom";

import MainBtns from "../Components/Buttons/MainBtns";
import InputForm from "../Components/Input/InputForm";

function IdentificationPage() {
  const navigate = useNavigate();

  return (
    <div style={{
    position: "absolute", 
    display:"flex",
    flexDirection: "column",
    right: "0", 
    top: "50%", 
    transform: "translateY(-50%)",
    maxWidth: "720px",
    maxHeight: "745px",
    alignItems: "center",
    width: "100%",
    height: "100%",
    
    }}>
      <p style={{display:"flex", justifyContent:"center", fontFamily:"Arial, sans-serif" ,fontSize:"32px", margin:"10px 10px 200px 10px"}}>Выполните вход чтобы продолжить</p>
      <InputForm TextPlaceholder="Адрес электронной почты"/>
      <InputForm TextPlaceholder={"Пароль"}/>
      <MainBtns Style={"purple-btn"} Text={"Продолжить"} Width={"400px"} Height={68} FontSize={"30px"} FontWeight={"100"} Padding={0} MarginTop={"auto"}  />
      <div style={{width:"500px", height:"100px", backgroundColor:"#F9F9FF", margin:"30px", display:"flex",flexDirection:"row", justifyContent:"center", alignItems: "center" }}>
        <div style={{display:"flex",flexDirection:"row"}}>Не зарегистрированы?&nbsp;<div style={{color:"var(--purple-btn-style-color)", TextDecorationStyle:"solid" }} onClick={()=>navigate("https://www.google.com/")}>Регистрирация</div></div>
      </div>
    </div>
  );
}

export default IdentificationPage;
